INSERT INTO `etat` (`id`, `titre`, `type_etat`, `periode_debut`, `periode_fin`, `contenu_ia`, `graphiques_data`, `parametres`, `statut`, `utilisateur`, `hash_cache`, `date_creation`, `date_modification`) VALUES
	(1, 'Résumé Exécutif - 01/08/2025', 'summary', '2025-08-01', NULL, '{"resume_executif": "Durante el periodo analizado se registraron 31 incidentes; sólo 13 quedaron resueltos, lo que arroja una tasa de resolución del 41,9 % y deja 5 casos aún abiertos. La mayor parte de los problemas (71 %) están relacionados con conectividad (sin Internet, Internet lento o mala red). El equipo de soporte muestra desigual rendimiento: Estelina cierra el 70 % de sus tickets, mientras que otros operadores no han resuelto ninguno.", "points_positifs": ["Estelina alcanza una tasa de resolución del 70 % (7/10), destacando sobre el resto del equipo", "La tipología de incidencias está claramente identificada, facilitando planes de acción focalizados", "El volumen total de incidentes es manejable (31), lo que permite intervenciones rápidas"], "points_attention": ["Tasa global de resolución inferior al 50 % (41,9 %), indicando posibles cuellos de botella en procesos o recursos", "5 incidentes permanecen abiertos sin SLA visible, riesgo de escalada o insatisfacción del cliente"], "recommandations": ["Establecer SLA claros y visibles para cada ticket abierto y asignar dueño único", "Replicar las buenas prácticas de Estelina mediante capacitación específica al resto del equipo", "Implementar script de diagnóstico rápido para problemas de conectividad y reducir el tiempo de resolución"], "kpis_cles": {"kpi1": "Tasa de resolución: 41,9 % (13/31) – indicador crítico de eficiencia del soporte", "kpi2": "Incidentes de conectividad: 71 % (22/31) – categoría dominante que requiere enfoque preventivo"}}', NULL, '{"periode": "current_month", "prompt_personnalise": "", "date_generation": "2025-08-01T15:04:36.998472", "usage": {"prompt_tokens": 428, "completion_tokens": 470, "total_tokens": 898, "prompt_tokens_details": null, "completion_tokens_details": null}}', 'generated', 'système', NULL, '2025-08-01 14:04:37', '2025-08-01 14:18:13'),
	(3, 'Estado de Julio', 'summary', '2025-07-01', '2025-07-31', '{"resume_executif": "Durante julio 2025 se registraron 968 incidentes de servicio técnico, de los cuales 530 fueron resueltos, alcanzando una tasa de resolución del 54.8%; el 44.6 % de los casos están relacionados con problemas de conectividad. Seis operadores atendieron la mayor parte de la carga, con un volumen mensual significativo que requiere optimización de recursos.", "points_positifs": ["Estelina y Cresencia lideran la atención con 161 y 159 incidentes resueltos respectivamente, mostrando alta productividad.", "Solo 8 incidentes permanecen en curso, lo que indica buen control de backlog.", "La categoría principal (SIN INTERNET) está claramente identificada, facilitando acciones focalizadas."], "points_attention": ["La tasa de resolución del 54.8 % está por debajo del estándar mínimo del 75 %.", "432 incidentes (44.6 %) son de tipo \\"SIN INTERNET\\", lo que puede señalar problemas de red recurrentes o insuficiencia de análisis preventivo.", "No se reporta tiempo medio de resolución, lo que impide medir la eficiencia real del servicio."], "recommandations": ["Establecer meta de tasa de resolución ≥ 75 % y revisar flujo de escalamiento para las 432 incidencias de \\"SIN INTERNET\\".", "Implementar monitoreo proactivo y análisis de causa raíz para reducir la reapertura de tickets de conectividad.", "Capturar y publicar el tiempo medio de resolución para identificar cuellos de botella y capacitar al equipo en áreas críticas."], "kpis_cles": {"kpi1": "54.8 % tasa de resolución mensual – indica que se cierra poco más de la mitad de los incidentes en el mismo mes.", "kpi2": "44.6 % de incidentes por pérdida total de internet – focaliza la intervención preventiva en infraestructura."}}', NULL, '{"periode": "last_month", "prompt_personnalise": "", "date_generation": "2025-08-01T15:26:09.394056", "usage": {"prompt_tokens": 481, "completion_tokens": 520, "total_tokens": 1001, "prompt_tokens_details": null, "completion_tokens_details": null}}', 'generated', 'sistema', NULL, '2025-08-01 14:26:09', '2025-08-01 14:26:17'),
	(4, 'Analyse des Tendances - 01/08/2025', 'analysis', '2025-07-01', '2025-07-31', '{"tendances_principales": ["Sin datos históricos, no se pueden identificar tendencias reales", "El mes analizado aún no ha ocurrido, lo que limita cualquier interpretación"], "patterns_temporels": {"jours": "No se detectaron patrones por día de la semana por falta de registros", "heures": "No se registró información suficiente para determinar horas pico"}, "predictions": ["Probable aumento de incidentes el primer día hábil del período", "Posible concentración de fallas en horario laboral matutino basado en estándares de la industria"], "actions_preventivas": ["Habilitar sistema de captura automática de incidentes desde el 01/07/2025", "Definir categorías estándar de incidentes para facilitar análisis futuro"]}', NULL, '{"periode": "last_month", "prompt_personnalise": "", "date_generation": "2025-08-01T15:34:51.721611", "usage": {"prompt_tokens": 269, "completion_tokens": 209, "total_tokens": 478, "prompt_tokens_details": null}}', 'generated', 'sistema', NULL, '2025-08-01 14:34:51', '2025-08-01 14:56:44'),
	(5, 'Rendimiento', 'performance', '2025-07-01', '2025-07-31', '{"resume_executif": "Durante julio-2025 el servicio técnico gestionó 968 incidentes, resolviendo el 54,8 % (530). El 87 % de los casos se agrupan en problemas de conectividad (sin internet, lento, inestable o mala red), lo que revela una fuerte concentración de demanda y oportunidades de mejora. El equipo de operadores muestra desempeño dispar: Estelina y Cresencia lideran volumen y eficiencia, mientras que Josefina Nseng aún no ha cerrado ninguno de sus 5 casos.", "points_positifs": ["Estelina y Cresencia solventan 33 % de todos los incidentes con tasas de éxito del 72 % y 55 % respectivamente", "El backlog abierto es mínimo: solo 8 incidentes en curso al cierre del período", "Se identificó claramente el foco de demanda (conectividad), lo que facilita planes de acción específicos"], "points_attention": ["Tasa de resolución global del 54,8 % está por debajo de la práctica estándar del sector (~75 %)", "Ausencia de dato de tiempo promedio de resolución imposibilita medir la experiencia del cliente y detectar cuellos de botella"], "recommandations": ["Implementar seguimiento semanal a los casos pendientes de Josefina Nseng y reasignar si es necesario para evitar SLA rotos", "Diseñar campaña de autodiagnóstico para problemas de conectividad que representan el 87 % de la demanda, reduciendo tickets repetitivos", "Establecer métrica de tiempo de resolución y panel en tiempo real que incluya tiempo de atención por tipo de incidencia"], "kpis_cles": {"kpi1": "87 % de incidentes relacionados con conectividad (sin internet, lento, inestable o mala red)", "kpi2": "54,8 % de tasa de resolución, 13,2 puntos porcentuales por debajo del benchmark recomendado"}}', NULL, '{"periode": "last_month", "prompt_personnalise": "", "date_generation": "2025-08-01T16:44:37.363980", "usage": {"prompt_tokens": 463, "completion_tokens": 523, "total_tokens": 986}}', 'generated', 'sistema', NULL, '2025-08-01 15:44:37', '2025-08-01 15:46:39'),
	(6, 'Résumé Exécutif - 02/08/2025', 'summary', '2025-07-21', '2025-07-27', '{"resume_executif": "Durante la semana 21-27/07/2025 se registraron 222 incidentes, de los cuales 131 fueron resueltos (59%). La mayoría de los casos corresponden a fallas de conectividad. No quedan incidentes abiertos, lo cual indica una gestión efectiva de cierre.", "points_positifs": ["Cierre total de todos los incidentes en curso (0 pendientes)", "Estelina alcanzó la más alta tasa de resolución individual (73,9%)", "La categorización permite identificar claramente que el 67% de los problemas son de falta o lentitud de Internet"], "points_attention": ["Baja tasa global de resolución (59%), por debajo del estándar habitual del 70-80%", "Duplicación de categorías (‘SIN INTERNET’ vs ‘SIN INTERNET ’ y otras) que distorsiona el análisis de tendencias"], "recommandations": ["Unificar nombres de categorías para evitar duplicados y mejorar la precisión analítica", "Implementar plan de mejora de resolución enfocado en Anja (16,7%) y Juanita (45%) mediante mentoring o capacitación", "Establecer seguimiento diario de incidentes críticos de conectividad para alzar la tasa de resolución por encima del 70%"], "kpis_cles": {"kpi1": "59.0% – Tasa de resolución de la semana, 11-21 puntos por debajo del benchmark", "kpi2": "200 – Total de incidentes de conectividad (sin Internet + Internet lento + mala red), representan 90% del volumen"}}', NULL, '{"periode": "last_week", "prompt_personnalise": "", "date_generation": "2025-08-02T12:21:51.651766", "usage": {"prompt_tokens": 458, "completion_tokens": 421, "total_tokens": 879}}', 'generated', 'sistema', NULL, '2025-08-02 11:21:51', '2025-08-02 11:22:25'),
	(7, 'Résumé Exécutif - 06/08/2025', 'summary', '2025-07-28', '2025-08-03', '{"resume_executif": "Durante la semana del 28/07 al 03/08/2025 se registraron 242 incidentes de servicio técnico, de los cuales sólo 53 % (129) se resolvieron, dejando 12 casos abiertos y una tasa de cierre por debajo del estándar mínimo del 70 %. El 82 % de los problemas están relacionados con fallas de conectividad (sin internet y revisión de conexión). El equipo de operadores muestra una amplia brecha de productividad, donde Estelina aporta casi el 40 % de la resolución total.", "points_positifs": ["Estelina lidera la resolución con 48 casos cerrados de 66 asignados (72,7 % efectividad)", "Cresencia y Restituta mantienen tasas de éxito superiores al 45 %", "No se reportaron re-abiertos ni escalamientos críticos durante la semana"], "points_attention": ["Tasa global de resolución de 53,3 % está 17 puntos por debajo del objetivo mínimo", "Falta de registro de tiempo promedio de resolución dificulta la gestión de SLA", "Alta concentración de fallas en \\"Sin Internet\\" (45,5 % del total) sugiere posible problema de infraestructura no identificado"], "recommandations": ["Establecer meta individual diaria de cierre de 15 casos para igualar la demanda de ingreso", "Implementar medición automática de TTR (Time To Resolution) en todas las incidencias", "Realizar análisis de causa raíz prioritario en los 100 casos de \\"Sin Internet\\" para prevenir reincidencias"], "kpis_cles": {"tasa_resolucion": "53,3 % (meta ≥ 70 %)", "incidentes_abiertos": "12 casos pendientes que deben cerrarse en < 24 h"}}', NULL, '{"periode": "last_week", "prompt_personnalise": "", "date_generation": "2025-08-06T21:02:20.191256", "usage": {"prompt_tokens": 475, "completion_tokens": 477, "total_tokens": 952, "prompt_tokens_details": null}}', 'generated', 'sistema', NULL, '2025-08-06 20:02:20', '2025-08-06 20:02:44'),
	(8, 'Résumé Exécutif - 25/08/2025', 'summary', '2025-08-18', '2025-08-24', '{"resume_executif": "Durante la semana 18–24/08/2025 el área de soporte registró 218 incidentes, de los cuales 122 fueron resueltos con una tasa de cierre del 56 %. La brecha más crítica se explica por la alta incidencia de interrupción de Internet (39,5 % del total).", "points_positifs": ["Cierre total de la cola de incidentes abiertos al término de la semana", "Estelina alcanzó un 75,9 % de efectividad, liderando el desempeño operativo", "Consolidación de datos de clasificación que permiten identificar patrones claros de falla"], "points_attention": ["43 % del volumen total sin resolución compromete la percepción de calidad de servicio", "Tres operadores (Anja, Hermes Okenve y Cresencia) muestran tasas de resolución inferiores al 60 %"], "recommandations": ["Establecer un plan de escalamiento inmediato para los 96 incidentes pendientes, priorizando tráfico crítico", "Implementar capacitación focalizada en diagnóstico de fallas de Internet y gestión de expectativas para Anja y Hermes", "Unificar criterios de clasificación y eliminar duplicados (ej. \\"SIN INTERNET\\" vs \\"Sin internet\\") para mejorar la precisión de los reportes"], "kpis_cles": {"kpi1": "56 % tasa de resolución semanal (meta ≥ 80 %)", "kpi2": "39,5 % de incidentes asociados a interrupción de Internet, indicando vulnerabilidad en la infraestructura de red"}}', NULL, '{"periode": "last_week", "prompt_personnalise": "", "date_generation": "2025-08-25T10:18:34.803961", "usage": {"prompt_tokens": 475, "completion_tokens": 421, "total_tokens": 896, "prompt_tokens_details": null}}', 'generated', 'sistema', NULL, '2025-08-25 10:18:34', '2025-08-25 09:18:54'),
	(9, 'Performance Opérateurs - 29/08/2025', 'performance', '2025-08-18', '2025-08-24', '{"resume_executif": "Durante la semana 18-24/08/2025 se registraron 218 incidentes de servicio, logrando resolver 122 casos con una tasa de resolución del 56 %. El 86 % de los problemas se concentran en la categoría \'Sin internet\', lo que indica un desafío recurrente en la conectividad. No hay incidentes en curso, lo que sugiere una gestión eficiente del backlog.", "points_positifs": ["Tasa de resolución del 56 % con backlog totalmente cerrado", "Estelina lidera el desempeño con 41 resoluciones de 54 casos (76 %)", "Cero incidentes en curso, evidenciando un flujo de trabajo disciplinado"], "points_attention": ["El 86 % de los incidentes son por falta de internet, indicando posible falla estructural", "Resolutores Anja y Hermes Okenve muestran 0 % de eficiencia (0/10 y 0/5)", "Tiempo promedio de resolución no reportado, lo que impide monitorear SLAs"], "recommandations": ["Investigar de inmediato la causa raíz de los 86 casos de \'Sin internet\' y ejecutar acciones preventivas", "Capacitar y acompañar a Anja y Hermes Okenve para alinear su rendimiento al promedio", "Implementar seguimiento automático del tiempo de resolución para garantizar métricas de SLA"], "kpis_cles": {"kpi1": "Tasa de resolución: 56 % – muestra la proporción de incidentes cerrados sobre el total", "kpi2": "Incidentes \'Sin internet\': 86 – representa el 39 % del total y es la fuente principal de inestabilidad"}}', NULL, '{"periode": "last_week", "prompt_personnalise": "", "date_generation": "2025-08-29T09:06:23.198981", "usage": {"prompt_tokens": 474, "completion_tokens": 439, "total_tokens": 913, "prompt_tokens_details": null, "completion_tokens_details": null}}', 'generated', 'sistema', NULL, '2025-08-29 09:06:23', '2025-08-29 08:06:30'),
	(10, 'Résumé Exécutif - 31/08/2025', 'summary', '2025-08-01', NULL, '{"resume_executif": "Durante el periodo analizado se registraron 1.014 incidentes, de los cuales 615 (60,7 %) han sido resueltos, dejando solo 1 incidente en curso. La gran mayoría de las solicitudes se concentran en problemas de conectividad (sin Internet, red mala o inestable), lo que indica oportunidades claras de mejora preventiva y automatización.", "points_positifs": ["Tasa de resolución cercana al 61 %, superando el umbral mínimo de 60 %", "Solo 1 incidente permanece abierto, lo que demuestra buen cierre de casos", "Estelina y Cresencia lideran el volumen de gestión con 217 y 181 incidentes resueltos respectivamente"], "points_attention": ["Problemas de conectividad agregan 794 casos (78 % del total), evidenciando fragilidad en la infraestructura de red", "Anja y Hermes Okenve muestran bajo desempeño relativo (7,5 % y 38 % de resolución), lo que puede indicar necesidad de capacitación o redistribución de carga"], "recommandations": ["Implementar diagnóstico remoto automático para los tipos “Sin Internet”, “Internet lento” y “Mala red” y reducir hasta un 30 % los tickets manuales", "Diseñar un plan de refuerzo de competencias para Anja y Hermes Okenve con seguimiento semanal de productividad", "Establecer alertas proactivas de red para anticipar incidencias masivas y disminuir el volumen de casos repetitivos"], "kpis_cles": {"kpi1": "60,7 % - Tasa de resolución global del periodo", "kpi2": "794 - Incidentes relacionados con conectividad (78 % del total)"}}', NULL, '{"periode": "current_month", "prompt_personnalise": "", "date_generation": "2025-08-31T23:44:33.780183", "usage": {"prompt_tokens": 467, "completion_tokens": 469, "total_tokens": 936}}', 'generated', 'sistema', NULL, '2025-08-31 23:44:33', '2025-08-31 22:45:05'),
	(11, 'Résumé Exécutif - 31/08/2025', 'summary', '2025-08-01', NULL, '{"resume_executif": "Durante el período analizado se registraron 1 014 incidentes, de los cuales 615 fueron resueltos (60,7 %), dejando solo 1 caso abierto. El 69 % de los problemas reportados se concentran en categorías relacionadas con conectividad (Sin Internet, Mala Red, Revisar/Verificar conexión). Estelina y Cresencia lideran la resolución con 217 y 181 casos cerrados respectivamente.", "points_positifs": ["Alta tasa de cierre global (60,7 %) con solo 1 incidente pendiente", "Estelina y Cresencia aportan el 64 % del total de resoluciones", "Clara identificación de las principales causas: problemas de conectividad"], "points_attention": ["Anja y Hermes Okenve muestran bajo rendimiento (7,5 % y 38 % de resolución)", "Duplicidad en la categoría \'Sin Internet\' puede distorsionar análisis", "Ausencia de dato de tiempo promedio de resolución limita la visibilidad de la eficiencia"], "recommandations": ["Unificar criterios de categorización para evitar duplicados (ej. \'Sin Internet\')", "Implementar plan de acompañamiento y capacitación para operadores con bajo desempeño", "Establecer métrica de tiempo promedio de resolución y fijar objetivo < 4 h para incidentes de conectividad"], "kpis_cles": {"kpi1": "60,7 % - Tasa de resolución global del período", "kpi2": "69 % - Proporción de incidentes relacionados con problemas de conectividad"}}', NULL, '{"periode": "current_month", "prompt_personnalise": "", "date_generation": "2025-08-31T23:44:39.737404", "usage": {"prompt_tokens": 486, "completion_tokens": 425, "total_tokens": 911, "prompt_tokens_details": null, "completion_tokens_details": null}}', 'generated', 'sistema', NULL, '2025-08-31 23:44:39', '2025-08-31 22:44:46');
